// Карточный каталог: slug → цена + название.
// Цены ДОЛЖНЫ совпадать с _data/guides.yml на сайте.
const CATALOG = {
  'relocation-english':   { title: 'Английский для релокации',                price: 2990 },
  'english-for-parents':  { title: 'Английский для родителей',                price: 2990 },
  'medical-english':      { title: 'Английский для медиков',                  price: 4990 },
  'it-interview-english': { title: 'English for Tech Interviews',             price: 2990 },
  'ai-first-english':     { title: 'AI-first English for Tech Stars',         price: 2490 },
  'legal-english':        { title: 'Legal English: Contracts & Compliance',   price: 5990 },
  'logistics-english':    { title: 'Logistic English',                        price: 3490 },
  'leadership-english':   { title: 'The language of Power — English for Leaders', price: 5490 }
};

// Куда возвращать после оплаты. Поменяй на боевой домен после переезда с GitHub Pages.
const RETURN_URL = 'https://nilolafeo-bit.github.io/special_english/thank-you/';

const body = items[0].json.body || items[0].json;
const slug = (body.guide_slug || '').toString();
const email = (body.email || '').toString().trim();
const idempotenceKey = (body.idempotence_key || '').toString();
const sourceUrl = (body.source_url || '').toString();

if (!slug || !CATALOG[slug]) {
  throw new Error('Unknown guide_slug: ' + slug);
}
if (!email || !/^\S+@\S+\.\S+$/.test(email)) {
  throw new Error('Invalid email');
}
if (!idempotenceKey) {
  throw new Error('Missing idempotence_key');
}

const product = CATALOG[slug];
const priceValue = product.price.toFixed(2); // 'NNNN.00'

return [{
  json: {
    guide_slug: slug,
    email,
    idempotence_key: idempotenceKey,
    source_url: sourceUrl,
    title: product.title,
    price_value: priceValue,
    description: 'Гайд: ' + product.title,
    return_url: RETURN_URL
  }
}];
